'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { useAuth } from '../../context/AuthContext';
import { ROUTES } from '../../lib/constants';
import Link from 'next/link';
import Image from 'next/image';
import { Menu } from 'lucide-react';

const Topbar = ({ setIsMobileOpen }) => {
  const router = useRouter();
  const { user, logout } = useAuth();
  const [searchQuery, setSearchQuery] = useState('');

  const handleSearch = (e) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      // Handle search functionality
      router.push(`/search?q=${encodeURIComponent(searchQuery)}`);
    }
  };

  return (
    <header className="bg-white dark:bg-gray-800 border-b border-gray-200 dark:border-gray-700 fixed top-0 left-0 right-0 z-50 w-full">
      <div className="w-full px-3 sm:px-6">
        <div className="flex items-center justify-between h-14">
          {/* Left Section - Logo */}
          <div className="flex items-center gap-2 sm:gap-4 flex-shrink-0">
            {/* Mobile Menu Button */}
            <button
              onClick={() => setIsMobileOpen(true)}
              className="lg:hidden p-1.5 sm:p-2 rounded-lg text-gray-600 hover:text-gray-900 hover:bg-gray-100 transition-colors duration-200"
              aria-label="Open sidebar"
            >
              <Menu size={20} />
            </button>

            <Link href={ROUTES.DASHBOARD}>
              <h1 className="text-lg sm:text-xl lg:text-2xl font-bold bg-clip-text text-bg-buttons-gradient cursor-pointer hover:opacity-80 transition-opacity">
                <span className="hidden sm:inline">Hyper Thread</span>
              </h1>
            </Link>
          </div>

          {/* Center Section - Search Bar */}
          <div className="flex-1 max-w-xs sm:max-w-md lg:max-w-2xl mx-2 sm:mx-4 lg:mx-8">
            <form onSubmit={handleSearch} className="relative">
              <div className="relative">
                <svg
                  className="absolute left-3 sm:left-4 top-1/2 transform -translate-y-1/2 w-4 h-4 sm:w-5 sm:h-5 text-gray-400"
                  fill="none"
                  stroke="currentColor"
                  viewBox="0 0 24 24"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={2}
                    d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"
                  />
                </svg>
                <input
                  type="text"
                  placeholder="Search"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full pl-10 sm:pl-12 pr-3 sm:pr-4 py-2 sm:py-3 text-sm sm:text-base bg-gray-50 dark:bg-gray-700 border border-gray-200 dark:border-gray-600 rounded-full text-gray-900 dark:text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all duration-200"
                />
              </div>
            </form>
          </div>

          {/* Right Section - Actions */}
          <div className="flex items-center gap-1 sm:gap-2 lg:gap-3 flex-shrink-0">
            {/* Create Button */}
            <Link href={ROUTES.CREATE_POST}>
              <button className="flex items-center gap-1 sm:gap-2 px-2 sm:px-3 lg:px-4 py-1.5 sm:py-2 text-xs sm:text-sm bg-buttons-gradient text-white border-none rounded-lg hover:bg-ui-cards-gradient hover:scale-105 transition-all duration-200 shadow-md">
                <svg className="w-3 h-3 sm:w-4 sm:h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                </svg>
                <span className="hidden md:inline">Create</span>
              </button>
            </Link>

            {/* Notifications - Hidden on very small screens */}
            <button className="hidden xs:block p-1.5 sm:p-2 text-gray-600 dark:text-gray-400 hover:text-white hover:bg-buttons-gradient rounded-lg transition-all duration-200 hover:scale-105">
              <svg className="w-4 h-4 sm:w-5 sm:h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-3.5-3.5a1.5 1.5 0 01-.44-1.06V9a6 6 0 00-6-6 6 6 0 00-6 6v3.44c0 .4-.16.78-.44 1.06L0 17h5m10 0v1a3 3 0 11-6 0v-1m6 0H9" />
              </svg>
            </button>

            {/* User Profile */}
            <div className="flex items-center">
              {user?.profileImage ? (
                <div className="rounded-full p-0.5 bg-buttons-gradient hover:bg-ui-cards-gradient hover:scale-105 transition-all duration-200 cursor-pointer">
                  <Image
                    src={user.profileImage}
                    alt={user.firstName}
                    width={30}
                    height={30}
                    className="rounded-full sm:w-[34px] sm:h-[34px]"
                  />
                </div>
              ) : (
                <button className="w-8 h-8 sm:w-9 sm:h-9 rounded-full bg-buttons-gradient flex items-center justify-center text-white font-semibold text-xs sm:text-sm hover:bg-ui-cards-gradient hover:scale-110 transition-all duration-200 shadow-md">
                  {user?.firstName?.[0]?.toUpperCase() || 'U'}
                </button>
              )}
            </div>
          </div>
        </div>
      </div>
    </header>
  );
};

export default Topbar;